Actionscript.script:
this._alpha = 0;
this.onRollOver = function()
{
   if(_parent.tmp_sz != undefined)
   {
      tmp_sz = _parent.tmp_sz;
   }
   else
   {
      tmp_sz = _root.根据物品名查找全部属性(_parent.item[1]);
   }
   _root.物品图标注释(tmp_sz[0],1);
   if(_root.商城主mc.展示框._visible == 1)
   {
      物品名字 = tmp_sz[0];
      物品小类别 = tmp_sz[3];
      _root.商城主mc.展示框.男模[物品小类别] = 物品名字;
      _root.商城主mc.展示框.女模[物品小类别] = 物品名字;
      if(_root.商城主mc.展示框.男模._visible == 1)
      {
         _root.商城主mc.刷新商城人物装扮("男模");
      }
      if(_root.商城主mc.展示框.女模._visible == 1)
      {
         _root.商城主mc.刷新商城人物装扮("女模");
      }
   }
};
this.onPress == function()
{
};
this.onRollOut = function()
{
   _root.注释结束();
};
